CREATE   PROCEDURE assoc.sp_BillingBatches_Delete @BatchId INT, @TenantId INT, @AssociationId INT AS BEGIN SET NOCOUNT ON; BEGIN TRANSACTION; BEGIN TRY IF NOT EXISTS (SELECT 1 FROM assoc.BillingBatches b WHERE b.BillingBatchId = @BatchId AND (b.Status IN ('Draft', 'COMMIT_FAILED') OR (b.Status = 'Committed' AND EXISTS (SELECT 1 FROM assoc.Invoices i WHERE i.BillingBatchId = b.BillingBatchId AND i.Status = 'Draft')))) BEGIN THROW 50000, 'Only Draft, Failed, or inconsistent batches can be deleted.', 1; END DELETE FROM assoc.InvoiceLineItems WHERE InvoiceId IN (SELECT InvoiceId FROM assoc.Invoices WHERE BillingBatchId = @BatchId); DELETE FROM assoc.Invoices WHERE BillingBatchId = @BatchId; DELETE FROM assoc.BillingBatches WHERE BillingBatchId = @BatchId; COMMIT TRANSACTION; END TRY BEGIN CATCH IF @@TRANCOUNT > 0 ROLLBACK; THROW; END CATCH END